  1→import React, { useState, useEffect } from 'react';
  2→import { AnalysisResult, User, SMCContent } from '../types';
  3→import { generateOptimizedRobotsTxt, parseCurrentRobotsTxt, getDetectedPlatformName } from '../services/robots_service';
  4→import { ArrowLeft, FileCode, Download, Copy, Check, Bot, ShieldCheck, AlertTriangle, RefreshCw, ChevronDown, History, Server, Eye, Settings, FileJson, Globe, Terminal, Lock, Zap, Archive } from 'lucide-react';
