  6→interface Props {
  7→  onBack: () => void;
  8→  history: AnalysisResult[];
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→  onUpdateAnalysis: (index: number, data: Partial<AnalysisResult>) => void;
 12→  savedFiles: SMCContent[];
 13→  onSaveFile: (item: SMCContent) => void;
 14→}
 15→
 16→const RobotsTxt: React.FC<Props> = ({ onBack, history, user, onDeductCredits, onUpdateAnalysis, savedFiles, onSaveFile }) => {
 17→  const [selectedAnalysisIndex, setSelectedAnalysisIndex] = useState<number>(0);
 18→  const [currentContent, setCurrentContent] = useState('');
 19→  const [optimizedContent, setOptimizedContent] = useState('');
 20→  const [platformName, setPlatformName] = useState('');
 21→  const [copied, setCopied] = useState(false);
 22→  const [isUnlocked, setIsUnlocked] = useState(false);
 23→
 24→  const GENERATION_COST = 10;
 25→
 26→  // Initialize with data from history
 27→  useEffect(() => {
 28→    const processUrl = (analysis: AnalysisResult | undefined) => {
 29→        if (!analysis) {
 30→            // Mode Demo / Fallback
 31→            const demoUrl = "https://monsite-wordpress.com";
 32→            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
 33→            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
 34→            setPlatformName(getDetectedPlatformName(demoUrl));
 35→            setIsUnlocked(false);
 36→            return;
 37→        }
 38→
 39→        const url = analysis.url;
 40→        setCurrentContent(parseCurrentRobotsTxt(url));
 41→        setPlatformName(getDetectedPlatformName(url));
 42→
 43→        // Check if previously unlocked/saved in history
 44→        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
 45→            setOptimizedContent(analysis.robotsTxtData.content);
 46→            setIsUnlocked(true);
 47→        } else {
 48→            // Fresh generation (locked)
 49→            setOptimizedContent(generateOptimizedRobotsTxt(url));
 50→            setIsUnlocked(false);
 51→        }
 52→    };
 53→
 54→    if (history.length > 0) {
 55→      processUrl(history[selectedAnalysisIndex]);
 56→    } else {
 57→      processUrl(undefined);
 58→    }
 59→  }, [selectedAnalysisIndex, history]);
 60→
 61→  const handleUnlock = () => {
 62→    // La vérification de connexion et de solde est gérée par onDeductCredits
 63→    if (onDeductCredits(GENERATION_COST)) {
 64→        setIsUnlocked(true);
 65→        
 66→        // Persist to analysis history
 67→        if (history.length > 0) {
 68→            onUpdateAnalysis(selectedAnalysisIndex, {
 69→                robotsTxtData: {
 70→                    content: optimizedContent,
 71→                    isUnlocked: true,
 72→                    platform: platformName,
 73→                    generatedAt: new Date().toISOString()
 74→                }
 75→            });
 76→        }
 77→
 78→        // Save to file history
 79→        onSaveFile({
 80→            id: `robots_${Date.now()}`,
 81→            type: 'fiche', // Generic
 82→            title: `Robots.txt - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
 83→            content: optimizedContent,
 84→            timestamp: new Date().toISOString()
 85→        });
 86→    }
 87→  };
 88→
 89→  const handleDownload = (filename?: string, content?: string) => {
 90→    const blob = new Blob([content || optimizedContent], { type: 'text/plain' });
 91→    const url = URL.createObjectURL(blob);
 92→    const a = document.createElement('a');
 93→    a.href = url;
 94→    a.download = filename || 'robots.txt';
 95→    document.body.appendChild(a);
 96→    a.click();
 97→    document.body.removeChild(a);
 98→    URL.revokeObjectURL(url);
 99→  };
