 14→const AI_BOTS: RobotRule[] = [
 15→  { agent: 'GPTBot', allow: true, comment: 'OpenAI (ChatGPT) - Essential for citation', category: 'ai' },
 16→  { agent: 'ChatGPT-User', allow: true, comment: 'OpenAI (Live Browsing)', category: 'ai' },
 17→  { agent: 'Google-Extended', allow: true, comment: 'Google Gemini/Vertex AI training', category: 'ai' },
 18→  { agent: 'CCBot', allow: true, comment: 'Common Crawl - Used by most LLMs foundation', category: 'ai' },
 19→  { agent: 'ClaudeBot', allow: true, comment: 'Anthropic (Claude)', category: 'ai' },
 20→  { agent: 'anthropic-ai', allow: true, comment: 'Anthropic (New agent)', category: 'ai' },
 21→  { agent: 'Applebot', allow: true, comment: 'Apple Intelligence / Siri', category: 'ai' },
 22→  { agent: 'PerplexityBot', allow: true, comment: 'Perplexity AI (Answer Engine)', category: 'ai' },
 23→  { agent: 'Amazonbot', allow: true, comment: 'Amazon Alexa / Q answers', category: 'ai' },
 24→  { agent: 'FacebookBot', allow: true, comment: 'Meta AI (Llama training)', category: 'ai' }
 25→];
